                rejected += 1; continue
            if cat == 'entertainment' and not client:
                rejected += 1; continue
            approved += min(amount, lim[cat] * days) if cat in lim else amount
        result = 'REJECT' if approved == 0 else 'PARTIAL' if rejected else 'APPROVE'
        rows.append({'id':r['id'],'result':result,'approved_amount':approved,'approval_level':'N/A' if approved == 0 else level(approved)})
print(json.dumps(rows, ensure_ascii=False, indent=2))
